// ================================================
// PAYROLL DISCREPANCY ENGINE
// Compares current pay run against previous period
// Flags anomalies before money is disbursed
// ================================================

const current = $('Get Current Pay Run').all().map(i => i.json);
const previous = $('Get Previous Pay Run').all().map(i => i.json);

// Build a lookup of last period by employee id
const prevById = {};
for (const row of previous) {
  const id = String(row.employee_id || row.employeeId || '').trim();
  if (id) prevById[id] = row;
}

const seenIds = new Set();
const results = [];

for (const row of current) {
  const empId = String(row.employee_id || row.employeeId || '').trim();
  const name = row.name || row.employee_name || 'Unknown';

  // Skip blank or disabled rows
  if (!empId || String(row.status || 'active').toLowerCase() === 'inactive') {
    continue;
  }

  if (seenIds.has(empId)) {
    results.push({
      json: {
        employeeId: empId,
        name,
        anomalyType: 'DUPLICATE_PAYMENT',
        severity: 'Critical',
        detail: 'Employee appears more than once in the current pay run.',
        currentNet: Number(row.net_pay || 0),
        previousNet: 0,
        deltaPct: 0,
        currentHours: Number(row.hours || 0),
        email: row.email || '',
        flagged: true
      }
    });
    continue;
  }
  seenIds.add(empId);

  const curNet = Number(row.net_pay || row.netPay || 0);
  const curHours = Number(row.hours || row.hours_worked || 0);
  const prev = prevById[empId];

  let anomalyType = '';
  let severity = '';
  let detail = '';
  let deltaPct = 0;

  if (!prev) {
    anomalyType = 'NEW_OR_UNMATCHED';
    severity = 'Medium';
    detail = 'No matching record in the previous pay run (new hire or ID mismatch).';
  } else {
    const prevNet = Number(prev.net_pay || prev.netPay || 0);
    deltaPct = prevNet > 0 ? Math.round(((curNet - prevNet) / prevNet) * 100) : 0;

    if (curHours === 0 && curNet > 0) {
      anomalyType = 'PAY_WITHOUT_HOURS';
      severity = 'High';
      detail = 'Net pay is greater than zero but logged hours are zero.';
    } else if (Math.abs(deltaPct) >= 40) {
      anomalyType = 'LARGE_PAY_SWING';
      severity = Math.abs(deltaPct) >= 80 ? 'Critical' : 'High';
      detail = 'Net pay changed by ' + deltaPct + ' percent versus last period.';
    } else if (Math.abs(deltaPct) >= 15) {
      anomalyType = 'MODERATE_PAY_CHANGE';
      severity = 'Medium';
      detail = 'Net pay changed by ' + deltaPct + ' percent versus last period.';
    }
  }

  if (anomalyType) {
    results.push({
      json: {
        employeeId: empId,
        name,
        anomalyType,
        severity,
        detail,
        currentNet: curNet,
        previousNet: prev ? Number(prev.net_pay || 0) : 0,
        deltaPct,
        currentHours: curHours,
        email: row.email || '',
        flagged: true
      }
    });
  }
}

// Sentinel so the IF node routes false when nothing is flagged
if (results.length === 0) {
  return [{ json: { flagged: false, anomalyType: 'none', severity: 'none', name: '', employeeId: '' } }];
}

return results;

