// ================================================
// RUN-LEVEL DIGEST BUILDER
// Aggregates all flagged anomalies into one summary
// ================================================

const items = $input.all().map(i => i.json);

let critical = 0, high = 0, medium = 0;
const lines = [];

for (const a of items) {
  if (a.severity === 'Critical') critical++;
  else if (a.severity === 'High') high++;
  else if (a.severity === 'Medium') medium++;
  if (a.lineSummary) lines.push('- ' + a.lineSummary);
}

const total = critical + high + medium;
const recommendation = critical > 0
  ? 'HOLD payroll - critical anomalies present.'
  : (high > 0 ? 'Review high-severity items before release.' : 'Minor items only - safe to proceed after a quick check.');

const digest = 'PAYROLL DISCREPANCY DIGEST\n\n'
  + 'Total flagged: ' + total + '\n'
  + 'Critical: ' + critical + ' | High: ' + high + ' | Medium: ' + medium + '\n\n'
  + 'Recommendation: ' + recommendation + '\n\n'
  + lines.join('\n');

return [{ json: { total, critical, high, medium, recommendation, digest } }];
